import logging
import logging.handlers
import os

# Set directory for log file
log_dir = '/path/to/log'  # Change to your desired log directory
os.makedirs(log_dir, exist_ok=True)

# Define log file path
log_file_path = os.path.join(log_dir, 'app.log')

# Create a logger
logger = logging.getLogger('MyAppLogger')
logger.setLevel(logging.DEBUG)

# Create a file handler with rotation
handler = logging.handlers.RotatingFileHandler(log_file_path, maxBytes=5*1024*1024, backupCount=5)
handler.setLevel(logging.DEBUG)

# Create a formatter and add it to the handler
formatter = logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s')
handler.setFormatter(formatter)

# Add the handler to the logger
logger.addHandler(handler)

# Set file permissions for log files
os.chmod(log_file_path, 0o640)

